import { useEffect, useRef, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";

const CACHE_KEY = "restaurant-name-translations";
const CACHE_VERSION = 1;

interface CacheEntry {
  v: number;
  data: Record<string, Record<string, string>>; // lang -> { id: translatedName }
}

function getCache(): Record<string, Record<string, string>> {
  try {
    const raw = localStorage.getItem(CACHE_KEY);
    if (!raw) return {};
    const parsed: CacheEntry = JSON.parse(raw);
    if (parsed.v !== CACHE_VERSION) return {};
    return parsed.data;
  } catch {
    return {};
  }
}

function setCache(data: Record<string, Record<string, string>>) {
  try {
    localStorage.setItem(CACHE_KEY, JSON.stringify({ v: CACHE_VERSION, data }));
  } catch {}
}

/**
 * Auto-translates restaurant/landmark names when the UI language doesn't match
 * any of the pre-stored name fields (name=zh, name_en, name_pt).
 * Results are cached in localStorage for persistence.
 */
export const useAutoTranslateNames = (
  restaurants: any[] | undefined,
  onTranslations: (translations: Record<string, string> | null) => void,
) => {
  const { i18n } = useTranslation();
  const lang = i18n.language;
  const translatingRef = useRef(false);
  const appliedIdsRef = useRef<string>("");
  const onTranslationsRef = useRef(onTranslations);
  onTranslationsRef.current = onTranslations;

  // Stable restaurant IDs string to avoid re-triggering on object reference changes
  const restaurantIds = restaurants?.map(r => r.id).join(",") || "";

  useEffect(() => {
    if (!restaurants || restaurants.length === 0) return;
    if (translatingRef.current) return;

    // Avoid re-applying for the same set of IDs + lang
    const cacheKey = `${lang}:${restaurantIds}`;
    if (appliedIdsRef.current === cacheKey) return;

    // Find restaurants that need name translation
    const needsTranslation = restaurants.filter((r) => {
      if (r.translations?.[lang]?.name) return false;
      if (lang === "zh") {
        return !!(r.name && r.name_en && r.name === r.name_en);
      }
      if (lang === "en") return !r.name_en;
      if (lang === "pt") return !r.name_pt;
      return true;
    });

    // Build a set of IDs that DON'T need translation (already have correct name in current lang)
    const skipIds = new Set<string>();
    restaurants.forEach((r) => {
      if (lang === "zh" && r.name && r.name_en && r.name !== r.name_en) {
        // Name is already Chinese (differs from English), don't override
        skipIds.add(r.id);
      } else if (lang === "en" && r.name_en) {
        skipIds.add(r.id);
      } else if (lang === "pt" && r.name_pt) {
        skipIds.add(r.id);
      }
    });

    // Apply existing cached translations (from DB translations or localStorage)
    // but skip restaurants that already have correct names in the current language
    const cache = getCache();
    const langCache = cache[lang] || {};
    const translationMap: Record<string, string> = {};
    let hasAny = false;

    for (const r of restaurants) {
      // Skip applying cache for restaurants that already have correct name
      if (skipIds.has(r.id)) continue;
      
      if (r.translations?.[lang]?.name) {
        translationMap[r.id] = `${r.translations[lang].name}\n${r.address || ""}`;
        hasAny = true;
      } else if (langCache[r.id]) {
        translationMap[r.id] = `${langCache[r.id]}\n${r.address || ""}`;
        hasAny = true;
      }
    }

    // Filter out already-cached items
    const uncached = needsTranslation.filter(
      (r) => !langCache[r.id] && !r.translations?.[lang]?.name,
    );

    if (hasAny) {
      appliedIdsRef.current = cacheKey;
      onTranslationsRef.current(translationMap);
    }

    if (uncached.length === 0) {
      appliedIdsRef.current = cacheKey;
      return;
    }

    const translateBatch = async () => {
      translatingRef.current = true;
      try {
        const batch = uncached.slice(0, 20);
        const separator = "\n---ITEM_SEPARATOR---\n";
        const combinedText = batch.map((r) => r.name_en || r.name).join(separator);

        const { data, error } = await supabase.functions.invoke("translate-content", {
          body: { text: combinedText, targetLang: lang },
        });

        if (error || !data?.translatedText) return;

        const translatedParts = data.translatedText.split(/---ITEM_SEPARATOR---/);
        const newCache = { ...getCache() };
        if (!newCache[lang]) newCache[lang] = {};

        const updatedMap = { ...translationMap };

        batch.forEach((r, index) => {
          const translatedName = (translatedParts[index] || r.name).trim();
          updatedMap[r.id] = `${translatedName}\n${r.address || ""}`;
          newCache[lang]![r.id] = translatedName;
        });

        setCache(newCache);
        appliedIdsRef.current = cacheKey;
        onTranslationsRef.current(updatedMap);
      } catch (err) {
        console.error("Auto-translate names error:", err);
      } finally {
        translatingRef.current = false;
      }
    };

    translateBatch();
  }, [restaurantIds, lang]);
};
